const body = $input.first().json.body || $input.first().json;
if (!body.account_id) throw new Error('account_id required');
return [{ json: {
  account_id: body.account_id,
  transcript: body.transcript_text || '',
  file_path: body.file_path || null
}}];

const prev = $('Normalize Input').first().json;
const memoJson = $input.first().json.stdout;
let v1Memo;
try { v1Memo = JSON.parse(memoJson); }
catch(e) { throw new Error(`Failed to parse v1 memo: ${e.message}`); }
return [{ json: { account_id: prev.account_id, transcript: prev.transcript, v1_memo: v1Memo } }];

// Rule-based patch extraction
const { account_id, transcript, v1_memo } = $json;
const changes = [];

// Deep copy v1 to start v2
const v2 = JSON.parse(JSON.stringify(v1_memo));

// 1. New phone number
const newPhoneMatch = transcript.match(/(?:new number is|changed to|updated to)\s+(\d{3}[-.]\d{3}[-.]\d{4})/i);
if (newPhoneMatch) {
  const phone = newPhoneMatch[1];
  const oldPhone = v2.emergency_routing_rules?.contacts?.[0]?.phone;
  if (oldPhone !== phone) {
    if (v2.emergency_routing_rules?.contacts?.[0]) {
      v2.emergency_routing_rules.contacts[0].phone = phone;
    }
    changes.push({ field: 'emergency_routing_rules.contacts[0].phone',
      action: 'update', old_value: oldPhone, new_value: phone,
      reason: 'New on-call number per onboarding' });
  }
}

// 2. New services
const svcMatches = [...transcript.matchAll(/(?:added|new service(?: line)?|now (?:also )?doing|new service:)\s+([^\.\n,]+)/gi)];
for (const m of svcMatches) {
  const svc = m[2].trim().replace(/\b\w/g, c=>c.toUpperCase());
  if (svc && !v2.services_supported.some(s => s.toLowerCase() === svc.toLowerCase())) {
    v2.services_supported.push(svc);
    changes.push({ field: 'services_supported', action: 'add',
      old_value: null, new_value: svc, reason: 'New service added in onboarding' });
  }
}

// 3. Address change
const addrMatch = transcript.match(/(?:new address|moved|address is now)[:\s]+([\d][^\n]+(?:Seattle|Austin|Phoenix|Denver|Houston|Suite|Ave|Street|Road|Blvd)[^\n]*)/i);
if (addrMatch) {
  const newAddr = addrMatch[1].trim();
  if (newAddr !== v2.office_address) {
    changes.push({ field: 'office_address', action: 'update',
      old_value: v2.office_address, new_value: newAddr, reason: 'Office address changed' });
    v2.office_address = newAddr;
  }
}

// 4. New contacts
const contactMatches = [...transcript.matchAll(/([A-Z][a-z]+\s+[A-Z][a-z]+)(?:[,\s]+at)?\s+(\d{3}[-.]\d{3}[-.]\d{4})/g)];
const existingPhones = new Set((v2.emergency_routing_rules?.contacts||[]).map(c=>c.phone));
for (const [, name, phone] of contactMatches) {
  if (!existingPhones.has(phone)) {
    const order = (v2.emergency_routing_rules?.contacts?.length || 0) + 1;
    v2.emergency_routing_rules = v2.emergency_routing_rules || {contacts:[]};
    v2.emergency_routing_rules.contacts = v2.emergency_routing_rules.contacts || [];
    v2.emergency_routing_rules.contacts.push({ name, phone, order });
    existingPhones.add(phone);
    changes.push({ field: `emergency_routing_rules.contacts[${order-1}]`,
      action: 'add', old_value: null, new_value: {name,phone,order},
      reason: 'New emergency contact added' });
  }
}

// 5. Saturday removal
if (/saturday.*(?:remov|no longer|not working|closed)/i.test(transcript)) {
  const old = v2.business_hours?.saturday;
  if (old) {
    v2.business_hours.saturday = null;
    changes.push({ field: 'business_hours.saturday', action: 'remove',
      old_value: old, new_value: null, reason: 'Saturday hours removed' });
  }
}

v2.version = 'v2';
v2.updated_at = new Date().toISOString();
v2.source_type = 'onboarding_call';

return [{ json: { account_id, v1_memo, v2_memo: v2, changes } }];

// Generate changelog JSON + markdown
const { account_id, v1_memo, v2_memo, changes } = $json;
const date = new Date().toISOString().slice(0,10);
const total = changes.length;
const added   = changes.filter(c=>c.action==='add').length;
const updated = changes.filter(c=>c.action==='update').length;
const removed = changes.filter(c=>c.action==='remove').length;

const changelog = {
  account_id, company_name: v2_memo.company_name,
  changelog_date: new Date().toISOString(),
  from_version: 'v1', to_version: 'v2',
  summary: { total_changes: total, added, updated, removed },
  changes,
  categorized: {
    added:   changes.filter(c=>c.action==='add'),
    updated: changes.filter(c=>c.action==='update'),
    removed: changes.filter(c=>c.action==='remove')
  }
};

let md = `# Changelog: ${v2_memo.company_name} (${account_id})\n`;
md += `**Date:** ${date}  |  **v1 → v2**\n`;
md += `**${total} change(s):** ${added} added, ${updated} updated, ${removed} removed\n\n---\n\n`;
for (const c of changes) {
  const icon = c.action==='add' ? '✅' : c.action==='remove' ? '❌' : '🔄';
  md += `${icon} **${c.field}** (${c.action})\n  _${c.reason}_\n\n`;
}

return [{ json: { account_id, v1_memo, v2_memo, changes, changelog, changelog_md: md } }];
